package com.example.service;

import com.example.domain.Comment;
import com.example.repo.CommentRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.Comparator;
import java.util.List;

@Service
public class CommentService {

    private final CommentRepository commentRepository;

    public CommentService(CommentRepository commentRepository) {
        this.commentRepository = commentRepository;
    }

    @Transactional(readOnly = true)
    public List<Comment> findAllForDisplay() {
        List<Comment> comments = commentRepository.findAll();
        comments.sort(Comparator.comparing(Comment::getCreatedAt).reversed());
        return comments;
    }
}

package com.example.repo;

import com.example.domain.Comment;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.jdbc.core.RowMapper;
import org.springframework.stereotype.Repository;

import java.sql.ResultSet;
import java.sql.SQLException;
import java.sql.Timestamp;
import java.time.Instant;
import java.util.List;

@Repository
public class CommentRepository {

    private final JdbcTemplate jdbcTemplate;

    public CommentRepository(JdbcTemplate jdbcTemplate) {
        this.jdbcTemplate = jdbcTemplate;
    }

    private static final RowMapper<Comment> COMMENT_ROW_MAPPER = new RowMapper<Comment>() {
        @Override
        public Comment mapRow(ResultSet rs, int rowNum) throws SQLException {
            Comment c = new Comment();
            c.setId(rs.getLong("id"));
            c.setAuthor(rs.getString("author"));
            c.setBodyHtml(rs.getString("body_html"));
            Timestamp ts = rs.getTimestamp("created_at");
            c.setCreatedAt(ts != null ? ts.toInstant() : Instant.EPOCH);
            return c;
        }
    };

    public List<Comment> findAll() {
        return jdbcTemplate.query(
                "SELECT id, author, body_html, created_at FROM comments ORDER BY created_at DESC",
                COMMENT_ROW_MAPPER
        );
    }
}

